{"method_body":"{
  result := "";
  var i := 0;
  while i < |s|
    invariant 0 <= i <= |s|
    invariant |result| == i
    invariant forall j :: 0 <= j < i ==> (if s[j] in ['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U'] then result[j] == '_' else result[j] == s[j])
  {
    var c := if s[i] in ['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U'] then '_' else s[i];
    result := result + [c];
    i := i + 1;
  }
}"}

